#[tokio::test]
async fn test_sysvar_spoofing_rejected() {
    // Feed a fake Clock sysvar at the correct address
    let fake_clock = construct_fake_clock_sysvar();
    let tx = Transaction::new_signed_with_payer(
        &[instruction_using_clock(&program_id, &fake_clock)],
        Some(&user.pubkey()),
        &[&user],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&tx).await;
    assert!(result.is_err());  // Must reject fake sysvar
}

#[tokio::test]
async fn test_authority_requires_signer() {
    let unsigned_tx = Transaction::new_signed_with_payer(
        &[privileged_instruction(&program_id, &attacker.pubkey())],
        Some(&attacker.pubkey()),
        &[&attacker],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&unsigned_tx).await;
    assert!(result.is_err());
}

#[test]
fn test_arithmetic_checked() {
    let max = u64::MAX;
    assert!(max.checked_add(1).is_none());
    assert!(0u64.checked_sub(1).is_none());
    assert!(max.checked_mul(max).is_none());
}

#[test]
fn test_canonical_bump_used() {
    let derived = ctx.bumps.get("vault").copied();
    assert!(derived.is_some(), "canonical bump must be in ctx.bumps");
}
